export const ascesaHtml = "\u003cdiv class=\"preloader\" id=\"preloader\"\u003e\n  \u003cdiv class=\"pre-inner\"\u003e\n    \u003cdiv class=\"pre-brand\"\u003eSan\u003cspan\u003eUp\u003c/span\u003e\u003c/div\u003e\n    \u003cdiv class=\"pre-track\"\u003e\u003cdiv class=\"pre-bar\" id=\"preBar\"\u003e\u003c/div\u003e\u003c/div\u003e\n    \u003cdiv class=\"pre-label\" id=\"preLabel\"\u003ePreparazione dell\u0027ascesa\u003c/div\u003e\n  \u003c/div\u003e\n\u003c/div\u003e\n\n\u003cdiv class=\"cursor\" id=\"cursor\"\u003e\u003c/div\u003e\n\n\u003cnav class=\"dots\" id=\"dots\" aria-label=\"Sezioni\"\u003e\u003c/nav\u003e\n\n\u003cdiv class=\"progress\" id=\"progress\"\u003e\u003c/div\u003e\n\u003ccanvas id=\"scene\"\u003e\u003c/canvas\u003e\n\u003cdiv class=\"scrim\"\u003e\u003c/div\u003e\n\u003cdiv class=\"vignette\"\u003e\u003c/div\u003e\n\n\u003cnav class=\"nav\"\u003e\n  \u003cdiv class=\"brand-row\"\u003e\n    \u003cimg class=\"logo-mark\" src=\"data:image/png;base64,\" width=\"34\" height=\"41\" alt=\"SanUp\"\u003e\n    \u003cdiv class=\"brand\"\u003eSan\u003cspan\u003eUp\u003c/span\u003e\u003c/div\u003e\n  \u003c/div\u003e\n  \u003ca class=\"nav-cta\" href=\"/home\"\u003eApri l\u0027app →\u003c/a\u003e\n\u003c/nav\u003e\n\n\u003cdiv class=\"scroll-ind\" id=\"scrollInd\"\u003e\n  \u003cdiv class=\"mouse\"\u003e\u003c/div\u003e\n  \u003cspan\u003eSCORRI\u003c/span\u003e\n\u003c/div\u003e\n\u003cdiv class=\"altitude\" id=\"altitude\"\u003eASCESA · 0%\u003c/div\u003e\n\n\u003cdiv class=\"weak-panel\" id=\"weakPanel\"\u003e\n  \u003ch4\u003eDiagnosi debolezze\u003c/h4\u003e\n  \u003cdiv class=\"hud-sub\" style=\"margin-bottom:10px\"\u003eEsempio illustrativo\u003c/div\u003e\n  \u003cdiv class=\"weak-row\"\u003e\u003cspan\u003eLogica\u003c/span\u003e\u003cdiv class=\"track\"\u003e\u003cdiv class=\"fill\" style=\"width:47%;background:#ff6b6b\"\u003e\u003c/div\u003e\u003c/div\u003e\u003cspan style=\"color:#ff8686\"\u003e47%\u003c/span\u003e\u003c/div\u003e\n  \u003cdiv class=\"weak-row\"\u003e\u003cspan\u003eFisica\u003c/span\u003e\u003cdiv class=\"track\"\u003e\u003cdiv class=\"fill\" style=\"width:58%;background:#febc2e\"\u003e\u003c/div\u003e\u003c/div\u003e\u003cspan style=\"color:#febc2e\"\u003e58%\u003c/span\u003e\u003c/div\u003e\n  \u003cdiv class=\"weak-row\"\u003e\u003cspan\u003eChimica\u003c/span\u003e\u003cdiv class=\"track\"\u003e\u003cdiv class=\"fill\" style=\"width:71%;background:#16C7C3\"\u003e\u003c/div\u003e\u003c/div\u003e\u003cspan style=\"color:#16C7C3\"\u003e71%\u003c/span\u003e\u003c/div\u003e\n  \u003cdiv class=\"weak-row\"\u003e\u003cspan\u003eBiologia\u003c/span\u003e\u003cdiv class=\"track\"\u003e\u003cdiv class=\"fill\" style=\"width:84%;background:#16C7C3\"\u003e\u003c/div\u003e\u003c/div\u003e\u003cspan style=\"color:#16C7C3\"\u003e84%\u003c/span\u003e\u003c/div\u003e\n\u003c/div\u003e\n\n\u003cdiv class=\"hud-panel\" id=\"examPanel\"\u003e\n  \u003cdiv class=\"hud-sub\"\u003eIl test d\u0027ammissione · formato MUR\u003c/div\u003e\n  \u003cdiv class=\"exam-row\"\u003e\u003cspan\u003eQuesiti\u003c/span\u003e\u003cb\u003e60\u003c/b\u003e\u003c/div\u003e\n  \u003cdiv class=\"exam-row\"\u003e\u003cspan\u003eTempo totale\u003c/span\u003e\u003cb\u003e100 minuti\u003c/b\u003e\u003c/div\u003e\n  \u003cdiv class=\"exam-row\"\u003e\u003cspan\u003eMaterie\u003c/span\u003e\u003cb\u003e6\u003c/b\u003e\u003c/div\u003e\n  \u003cdiv class=\"exam-row\"\u003e\u003cspan\u003eFeedback durante la prova\u003c/span\u003e\u003cb\u003eNessuno\u003c/b\u003e\u003c/div\u003e\n  \u003cdiv class=\"hud-scoring\"\u003e\n    \u003cdiv class=\"hud-chip pos\"\u003e+1,5\u003csmall\u003ecorretta\u003c/small\u003e\u003c/div\u003e\n    \u003cdiv class=\"hud-chip neg\"\u003e−0,4\u003csmall\u003eerrata\u003c/small\u003e\u003c/div\u003e\n    \u003cdiv class=\"hud-chip neu\"\u003e0\u003csmall\u003eomessa\u003c/small\u003e\u003c/div\u003e\n  \u003c/div\u003e\n\u003c/div\u003e\n\n\u003cdiv class=\"content\"\u003e\n\n  \u003csection class=\"section\"\u003e\n    \u003cdiv class=\"block\"\u003e\n      \u003cdiv class=\"eyebrow\"\u003eTSRM · Professioni Sanitarie · MUR\u003c/div\u003e\n      \u003ch1\u003eNon un quiz.\u003cbr\u003e\u003cspan class=\"grad\"\u003eUn\u0027ascesa.\u003c/span\u003e\u003c/h1\u003e\n      \u003cp\u003eSanUp costruisce la sequenza esatta della tua preparazione e ti porta al test di ammissione un gradino alla volta — come scalare una struttura, fino in cima.\u003c/p\u003e\n      \u003cdiv class=\"cta-row\"\u003e\n        \u003ca class=\"btn btn-primary\" href=\"/allenati\"\u003eInizia a studiare →\u003c/a\u003e\n        \u003ca class=\"btn btn-ghost\" href=\"#\"\u003eCome funziona ↓\u003c/a\u003e\n      \u003c/div\u003e\n    \u003c/div\u003e\n  \u003c/section\u003e\n\n  \u003csection class=\"section\"\u003e\n    \u003cdiv class=\"block\"\u003e\n      \u003cdiv class=\"eyebrow\"\u003e01 · La struttura\u003c/div\u003e\n      \u003ch2\u003eSei materie.\u003cbr\u003e\u003cspan class=\"grad\"\u003eUn\u0027unica sequenza.\u003c/span\u003e\u003c/h2\u003e\n      \u003cp\u003eBiologia, Chimica, Fisica, Matematica, Logica, Cultura generale: SanUp le collega in un percorso continuo dove ogni argomento aggancia il successivo — niente studio a compartimenti stagni.\u003c/p\u003e\n      \u003cdiv class=\"stats\"\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e6\u003c/div\u003e\u003cdiv class=\"lab\"\u003ematerie\u003c/div\u003e\u003c/div\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e60\u003c/div\u003e\u003cdiv class=\"lab\"\u003equesiti / prova\u003c/div\u003e\u003c/div\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e100\u0027\u003c/div\u003e\u003cdiv class=\"lab\"\u003ecome al MUR\u003c/div\u003e\u003c/div\u003e\n      \u003c/div\u003e\n    \u003c/div\u003e\n  \u003c/section\u003e\n\n  \u003csection class=\"section\"\u003e\n    \u003cdiv class=\"block\"\u003e\n      \u003cdiv class=\"eyebrow\"\u003e02 · Dentro la struttura\u003c/div\u003e\n      \u003ch2\u003eOgni errore\u003cbr\u003e\u003cspan class=\"grad\"\u003ediventa un gradino.\u003c/span\u003e\u003c/h2\u003e\n      \u003cp\u003eSbagli, e SanUp ti spiega il perché — risposta corretta, trappola del test, concetto da ricordare. Poi ti ripropone l\u0027errore finché non lo padroneggi. È così che si sale.\u003c/p\u003e\n      \u003cdiv class=\"stats\"\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e+1,5\u003c/div\u003e\u003cdiv class=\"lab\"\u003ecorretta\u003c/div\u003e\u003c/div\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e−0,4\u003c/div\u003e\u003cdiv class=\"lab\"\u003eerrata\u003c/div\u003e\u003c/div\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e0\u003c/div\u003e\u003cdiv class=\"lab\"\u003ebianca\u003c/div\u003e\u003c/div\u003e\n      \u003c/div\u003e\n    \u003c/div\u003e\n  \u003c/section\u003e\n\n  \u003csection class=\"section\"\u003e\n    \u003cdiv class=\"block\"\u003e\n      \u003cdiv class=\"eyebrow\"\u003e03 · Il tuo progresso\u003c/div\u003e\n      \u003ch2\u003eSessioni, errori,\u003cbr\u003e\u003cspan class=\"grad\"\u003etutto tracciato.\u003c/span\u003e\u003c/h2\u003e\n      \u003cp\u003eOgni sessione viene registrata con la tua percentuale di risposte corrette. Gli errori restano tracciati per materia — puoi marcarli risolti uno per uno quando sei pronto. Le domande interessanti si salvano con un tap.\u003c/p\u003e\n      \u003cdiv class=\"stats\"\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e%\u003c/div\u003e\u003cdiv class=\"lab\"\u003eaccuratezza\u003c/div\u003e\u003c/div\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e✓\u003c/div\u003e\u003cdiv class=\"lab\"\u003eerrori\u003c/div\u003e\u003c/div\u003e\n        \u003cdiv class=\"stat\"\u003e\u003cdiv class=\"num\"\u003e🔖\u003c/div\u003e\u003cdiv class=\"lab\"\u003esalvate\u003c/div\u003e\u003c/div\u003e\n      \u003c/div\u003e\n    \u003c/div\u003e\n  \u003c/section\u003e\n\n  \u003csection class=\"section showcase\" id=\"showcase\"\u003e\n    \u003cdiv class=\"block\"\u003e\n      \u003cdiv class=\"eyebrow\"\u003e04 · L\u0027app\u003c/div\u003e\n      \u003ch2\u003eStudi qui.\u003cbr\u003e\u003cspan class=\"grad\"\u003eTutto in un posto.\u003c/span\u003e\u003c/h2\u003e\n      \u003cp\u003eRispondi, capisci l\u0027errore, vedi i tuoi progressi. Tre gesti, una risalita continua — dal primo quesito fino al giorno del test.\u003c/p\u003e\n    \u003c/div\u003e\n    \u003cdiv class=\"phones\"\u003e\n\n      \u003cdiv class=\"phone\"\u003e\n        \u003cdiv class=\"phone-screen\"\u003e\n          \u003cdiv class=\"ph-top\"\u003e\u003cspan class=\"ph-tag\"\u003eBiologia\u003c/span\u003e\u003cspan class=\"ph-count\"\u003e12 / 60\u003c/span\u003e\u003c/div\u003e\n          \u003cdiv class=\"ph-prog\"\u003e\u003ci style=\"width:20%\"\u003e\u003c/i\u003e\u003c/div\u003e\n          \u003cdiv class=\"ph-q\"\u003eQuale organello è responsabile della sintesi proteica nella cellula?\u003c/div\u003e\n          \u003cdiv class=\"ph-opts\"\u003e\n            \u003cdiv class=\"ph-opt\"\u003eA · Mitocondrio\u003c/div\u003e\n            \u003cdiv class=\"ph-opt sel\"\u003eB · Ribosoma\u003c/div\u003e\n            \u003cdiv class=\"ph-opt\"\u003eC · Apparato di Golgi\u003c/div\u003e\n            \u003cdiv class=\"ph-opt\"\u003eD · Lisosoma\u003c/div\u003e\n          \u003c/div\u003e\n          \u003cdiv class=\"ph-btn\"\u003eConferma\u003c/div\u003e\n        \u003c/div\u003e\n      \u003c/div\u003e\n\n      \u003cdiv class=\"phone mid\"\u003e\n        \u003cdiv class=\"phone-screen\"\u003e\n          \u003cdiv class=\"ph-top\"\u003e\u003cspan class=\"ph-tag\"\u003eBiologia\u003c/span\u003e\u003cspan class=\"ph-count\"\u003e12 / 60\u003c/span\u003e\u003c/div\u003e\n          \u003cdiv class=\"ph-verdict ok\"\u003eCorretta · +1,5\u003c/div\u003e\n          \u003cdiv class=\"ph-opts\"\u003e\n            \u003cdiv class=\"ph-opt correct\"\u003eB · Ribosoma ✓\u003c/div\u003e\n          \u003c/div\u003e\n          \u003cdiv class=\"ph-expl\"\u003e\n            \u003cdiv class=\"ph-expl-t\"\u003ePerché\u003c/div\u003e\n            I ribosomi traducono l\u0027mRNA assemblando le catene polipeptidiche. I mitocondri producono ATP: energia, non proteine strutturali.\n          \u003c/div\u003e\n          \u003cdiv class=\"ph-btn\"\u003eAvanti →\u003c/div\u003e\n        \u003c/div\u003e\n      \u003c/div\u003e\n\n      \u003cdiv class=\"phone\"\u003e\n        \u003cdiv class=\"phone-screen\"\u003e\n          \u003cdiv class=\"ph-top\"\u003e\u003cspan class=\"ph-tag\"\u003eI tuoi progressi\u003c/span\u003e\u003c/div\u003e\n          \u003cdiv class=\"ph-ring\"\u003e\u003cspan\u003e78%\u003c/span\u003e\u003csmall\u003eaccuratezza\u003c/small\u003e\u003c/div\u003e\n          \u003cdiv class=\"ph-bars\"\u003e\n            \u003cdiv class=\"ph-bar\"\u003e\u003cspan\u003eBiologia\u003c/span\u003e\u003ci style=\"--v:84%\"\u003e\u003c/i\u003e\u003c/div\u003e\n            \u003cdiv class=\"ph-bar\"\u003e\u003cspan\u003eChimica\u003c/span\u003e\u003ci style=\"--v:71%\"\u003e\u003c/i\u003e\u003c/div\u003e\n            \u003cdiv class=\"ph-bar\"\u003e\u003cspan\u003eFisica\u003c/span\u003e\u003ci style=\"--v:58%\"\u003e\u003c/i\u003e\u003c/div\u003e\n            \u003cdiv class=\"ph-bar\"\u003e\u003cspan\u003eLogica\u003c/span\u003e\u003ci style=\"--v:47%\"\u003e\u003c/i\u003e\u003c/div\u003e\n          \u003c/div\u003e\n          \u003cdiv class=\"ph-stats\"\u003e\n            \u003cdiv\u003e\u003cb\u003e24\u003c/b\u003esessioni\u003c/div\u003e\n            \u003cdiv\u003e\u003cb\u003e18\u003c/b\u003eerrori\u003c/div\u003e\n            \u003cdiv\u003e\u003cb\u003e36\u003c/b\u003esalvate\u003c/div\u003e\n          \u003c/div\u003e\n        \u003c/div\u003e\n      \u003c/div\u003e\n\n    \u003c/div\u003e\n  \u003c/section\u003e\n\n  \u003csection class=\"section subjects-section\" id=\"subjects\"\u003e\n    \u003cdiv class=\"block subjects-block\"\u003e\n      \u003cdiv class=\"eyebrow\"\u003e05 · La cima\u003c/div\u003e\n      \u003ch2\u003ePreparati al futuro\u003cbr\u003e\u003cspan class=\"grad\"\u003eche meriti.\u003c/span\u003e\u003c/h2\u003e\n      \u003cp\u003e1.500 domande originali. 6 materie. Spiegazione per ogni risposta. Nessun abbonamento.\u003c/p\u003e\n      \u003cdiv class=\"cta-row\" style=\"justify-content:center\"\u003e\n        \u003ca class=\"btn btn-primary\" href=\"/allenati\"\u003eInizia a studiare →\u003c/a\u003e\n      \u003c/div\u003e\n    \u003c/div\u003e\n    \u003cdiv class=\"subjects-grid\"\u003e\n      \u003cdiv class=\"sub-card\"\u003e\u003cdiv class=\"sub-icon\"\u003e🔬\u003c/div\u003e\u003cdiv class=\"sub-name\"\u003eBiologia\u003c/div\u003e\u003cdiv class=\"sub-count\"\u003e360\u003cspan\u003edomande\u003c/span\u003e\u003c/div\u003e\u003c/div\u003e\n      \u003cdiv class=\"sub-card\"\u003e\u003cdiv class=\"sub-icon\"\u003e⚗️\u003c/div\u003e\u003cdiv class=\"sub-name\"\u003eChimica\u003c/div\u003e\u003cdiv class=\"sub-count\"\u003e300\u003cspan\u003edomande\u003c/span\u003e\u003c/div\u003e\u003c/div\u003e\n      \u003cdiv class=\"sub-card\"\u003e\u003cdiv class=\"sub-icon\"\u003e⚛️\u003c/div\u003e\u003cdiv class=\"sub-name\"\u003eFisica\u003c/div\u003e\u003cdiv class=\"sub-count\"\u003e230\u003cspan\u003edomande\u003c/span\u003e\u003c/div\u003e\u003c/div\u003e\n      \u003cdiv class=\"sub-card\"\u003e\u003cdiv class=\"sub-icon\"\u003e📐\u003c/div\u003e\u003cdiv class=\"sub-name\"\u003eMatematica\u003c/div\u003e\u003cdiv class=\"sub-count\"\u003e210\u003cspan\u003edomande\u003c/span\u003e\u003c/div\u003e\u003c/div\u003e\n      \u003cdiv class=\"sub-card\"\u003e\u003cdiv class=\"sub-icon\"\u003e🧩\u003c/div\u003e\u003cdiv class=\"sub-name\"\u003eLogica\u003c/div\u003e\u003cdiv class=\"sub-count\"\u003e200\u003cspan\u003edomande\u003c/span\u003e\u003c/div\u003e\u003c/div\u003e\n      \u003cdiv class=\"sub-card\"\u003e\u003cdiv class=\"sub-icon\"\u003e📖\u003c/div\u003e\u003cdiv class=\"sub-name\"\u003eCultura gen.\u003c/div\u003e\u003cdiv class=\"sub-count\"\u003e200\u003cspan\u003edomande\u003c/span\u003e\u003c/div\u003e\u003c/div\u003e\n    \u003c/div\u003e\n  \u003c/section\u003e\n\n\u003c/div\u003e";

